+                    let bg = tinted
+                        .bg
+                        .expect("result-row style should always define background");
+                    let ratio = ftui::style::contrast_ratio_packed(fg, bg);
+                    assert!(
+                        ratio >= 4.5,
+                        "text contrast {:.2} below threshold for preset {} token {} agent {}",
+                        ratio,
+                        preset.name(),
+                        base_token,
+                        agent
